        if redirect_uri in client.registered_redirect_uris:
            return True

        # ---------------------------------------------------------------
        # DELIBERATELY NOT IMPLEMENTING prefix matching. Example of the
        # INSECURE pattern we are avoiding:
        #
        #   # INSECURE — DO NOT USE:
        #   # for registered_uri in client.registered_redirect_uris:
        #   #     if redirect_uri.startswith(registered_uri):
        #   #         return True
        #
        # This would allow open redirect attacks.
        # ---------------------------------------------------------------

