    # -------------------------------------------------------------------------
    # Authorization Endpoint
    # -------------------------------------------------------------------------

    def authorize(
        self,
        client_id: str,
        redirect_uri: str,
        response_type: str,
        scope: str,
        state: str,
        user_id: str,
        code_challenge: Optional[str] = None,
        code_challenge_method: Optional[str] = None,
    ) -> dict:
        """
        Authorization endpoint — issues an authorization code after validating
        the redirect URI with EXACT matching.
        """
        # Validate client exists
        client = self._clients.get(client_id)
        if not client:
            # Per RFC 6749 §4.1.2.1: If client_id is invalid, do NOT redirect
            raise OAuthError("invalid_client", "Unknown client_id")

        # SECURE redirect URI validation (exact match)
        if not self._validate_redirect_uri(client, redirect_uri):
            # Per RFC 6749 §4.1.2.1: If redirect_uri is invalid, do NOT redirect
            # Instead, inform the resource owner directly
            raise RedirectURIValidationError(
                f"redirect_uri '{redirect_uri}' does not exactly match any registered URI. "
                f"Registered URIs: {client.registered_redirect_uris}"
            )

        if response_type != "code":
            return self._build_error_redirect(
                redirect_uri, "unsupported_response_type",
                "Only 'code' response_type is supported", state
            )

        # Validate scopes
        requested_scopes = set(scope.split())
        if not requested_scopes.issubset(client.allowed_scopes):
            return self._build_error_redirect(
                redirect_uri, "invalid_scope", "Requested scope exceeds allowed scopes", state
            )

        # Generate authorization code
        code = secrets.token_urlsafe(32)
        self._authorization_codes[code] = AuthorizationCode(
            code=code,
            client_id=client_id,
            redirect_uri=redirect_uri,
            scope=scope,
            user_id=user_id,
            expires_at=time.time() + 600,  # 10 minutes
            code_challenge=code_challenge,
            code_challenge_method=code_challenge_method,
        )

        # Build redirect with authorization code
        parsed = urllib.parse.urlparse(redirect_uri)
        params = urllib.parse.parse_qs(parsed.query)
        params["code"] = [code]
        params["state"] = [state]
        new_query = urllib.parse.urlencode(params, doseq=True)
        final_uri = urllib.parse.urlunparse(parsed._replace(query=new_query))

        print(f"[AUTHORIZE] Code issued for client '{client.client_name}', user '{user_id}'")
        print(f"  redirect_uri (exact match verified): {redirect_uri}")

        return {"redirect_to": final_uri, "code": code}

    # -------------------------------------------------------------------------
    # Token Endpoint
    # -------------------------------------------------------------------------

    def token(
        self,
        grant_type: str,
        client_id: str,
        client_secret: str,
        code: Optional[str] = None,
        redirect_uri: Optional[str] = None,
        code_verifier: Optional[str] = None,
        refresh_token: Optional[str] = None,
    ) -> dict:
        """Token endpoint — exchanges authorization code for tokens."""
        # Authenticate client
        client = self._clients.get(client_id)
        if not client:
            raise OAuthError("invalid_client", "Unknown client_id")

        secret_hash = hashlib.sha256(client_secret.encode()).hexdigest()
        if not secrets.compare_digest(secret_hash, client.client_secret_hash):
            raise OAuthError("invalid_client", "Invalid client_secret")

        if grant_type == "authorization_code":
            return self._handle_authorization_code_grant(
                client, code, redirect_uri, code_verifier
            )
        elif grant_type == "refresh_token":
            return self._handle_refresh_token_grant(client, refresh_token)
        else:
            raise OAuthError("unsupported_grant_type", f"Grant type '{grant_type}' not supported")

    def _handle_authorization_code_grant(
        self,
        client: OAuthClient,
        code: Optional[str],
        redirect_uri: Optional[str],
        code_verifier: Optional[str],
    ) -> dict:
        if not code:
            raise OAuthError("invalid_request", "Missing authorization code")

        auth_code = self._authorization_codes.get(code)
        if not auth_code:
            raise OAuthError("invalid_grant", "Invalid authorization code")

        if auth_code.used:
            # Code reuse detected — revoke all tokens for this code (security measure)
            raise OAuthError("invalid_grant", "Authorization code already used")

        if auth_code.client_id != client.client_id:
            raise OAuthError("invalid_grant", "Code was not issued to this client")

        if time.time() > auth_code.expires_at:
            raise OAuthError("invalid_grant", "Authorization code expired")

        # Verify redirect_uri matches exactly what was used in authorization request
        if redirect_uri and redirect_uri != auth_code.redirect_uri:
            raise OAuthError("invalid_grant", "redirect_uri does not match authorization request")

        # PKCE verification
